</TabItem>
<TabItem label="PHP">

```php
<?php
$ch = curl_init('https://api.echovalue.dev/kv/default/mykey');
curl_setopt($ch, CURLOPT_HTTPHEADER, ['x-token: mytoken']);
curl_setopt($ch, CURLOPT_RETURNTRANSFER, true);
curl_setopt($ch, CURLOPT_HEADER, true);

$response = curl_exec($ch);
$headerSize = curl_getinfo($ch, CURLINFO_HEADER_SIZE);
$headers = substr($response, 0, $headerSize);
curl_close($ch);

// Parse x-balance from headers
preg_match('/x-balance:\s*(\d+)/i', $headers, $matches);
echo 'Balance: ' . $matches[1];
?>
```

</TabItem>
<TabItem label="Go">

```go
package main

import (
    "fmt"
    "net/http"
)

func main() {
    req, _ := http.NewRequest("GET", "https://api.echovalue.dev/kv/default/mykey", nil)
    req.Header.Set("x-token", "mytoken")

    client := &http.Client{}
    resp, _ := client.Do(req)
    defer resp.Body.Close()

    fmt.Println("Cost:", resp.Header.Get("x-cost"))
    fmt.Println("Balance:", resp.Header.Get("x-balance"))
}
```

